func newProjectService_ListProjectGrantsCmd(getCfg func() *config.Config, getOutput func() string) *cobra.Command {
	var flag_ListProjectGrants_SortingColumn string
	var convFilter_ListProjectGrants_OrganizationIdFilter string
	var convFilter_ListProjectGrants_GrantedOrganizationIdFilter string

	cmd := &cobra.Command{
		Use:     "list-grants",
		Short:   "List project grants",
		Long:    "List Project Grants",
		Example: "  projects list-grants --sorting-column PROJECT_GRANT_FIELD_NAME_UNSPECIFIED",
		RunE: func(cmd *cobra.Command, args []string) error {
			req := &projectpb.ListProjectGrantsRequest{}

			// Check for JSON input via --from-json or --request-json flags
			useJSON, _ := cmd.Flags().GetBool("from-json")
			requestJSON, _ := cmd.Flags().GetString("request-json")
			if requestJSON != "" {
				useJSON = true
			}
			if useJSON {
				var data []byte
				if requestJSON != "" {
					data = []byte(requestJSON)
				} else {
					var err error
					data, err = io.ReadAll(os.Stdin)
					if err != nil {
						return fmt.Errorf("reading stdin: %w", err)
					}
				}
				if err := protojson.Unmarshal(data, req); err != nil {
					return fmt.Errorf("parsing JSON input: %w", err)
				}
			}

			if !useJSON {
				if flag_ListProjectGrants_SortingColumn != "" {
					enumVal, ok := projectpb.ProjectGrantFieldName_value[flag_ListProjectGrants_SortingColumn]
					if !ok {
						return fmt.Errorf("invalid value %q for --sorting-column", flag_ListProjectGrants_SortingColumn)
					}
					ev := projectpb.ProjectGrantFieldName(enumVal)
					req.SortingColumn = &ev
				}
			}

			// Convenience filter: --organization-id → OrganizationIdFilter in Filters
			if convFilter_ListProjectGrants_OrganizationIdFilter != "" {
				req.Filters = append(req.Filters, &projectpb.ProjectGrantSearchFilter{
					Filter: &projectpb.ProjectGrantSearchFilter_OrganizationIdFilter{
						OrganizationIdFilter: &filterv2.IDFilter{Id: convFilter_ListProjectGrants_OrganizationIdFilter},
					},
				})
			}

			// Convenience filter: --granted-organization-id → GrantedOrganizationIdFilter in Filters
			if convFilter_ListProjectGrants_GrantedOrganizationIdFilter != "" {
				req.Filters = append(req.Filters, &projectpb.ProjectGrantSearchFilter{
					Filter: &projectpb.ProjectGrantSearchFilter_GrantedOrganizationIdFilter{
						GrantedOrganizationIdFilter: &filterv2.IDFilter{Id: convFilter_ListProjectGrants_GrantedOrganizationIdFilter},
					},
				})
			}

			// Dry-run: print request and exit without calling the API
			dryRun, _ := cmd.Flags().GetBool("dry-run")
			if dryRun {
				reqJSON, err := protojson.MarshalOptions{Indent: "  "}.Marshal(req)
				if err != nil {
					return fmt.Errorf("marshalling request: %w", err)
				}
				envelope := map[string]json.RawMessage{
					"method":  json.RawMessage(fmt.Sprintf("%q", "zitadel.project.v2.ProjectService/ListProjectGrants")),
					"request": json.RawMessage(reqJSON),
				}
				out, _ := json.MarshalIndent(envelope, "", "  ")
				fmt.Println(string(out))
				return nil
			}

			cfg := getCfg()
			actx, _, err := config.ActiveCtx(cfg)
			if err != nil {
				return err
			}
			tokenSource, err := auth.TokenSource(cmd.Context(), actx)
			if err != nil {
				return err
			}
			httpClient := client.New(tokenSource)
			baseURL := client.InstanceURL(actx.Instance)
			svcClient := projectconnect.NewProjectServiceClient(httpClient, baseURL)

			resp, err := svcClient.ListProjectGrants(cmd.Context(), connect.NewRequest(req))
			if err != nil {
				return FormatConnectError(err)
			}

			if getOutput() == "json" {
				return output.JSON(resp.Msg)
			}

			header := []string{"ORGANIZATION ID", "GRANTED ORGANIZATION ID", "PROJECT ID", "GRANTED ORGANIZATION NAME", "PROJECT NAME", "STATE", "CREATION DATE", "CHANGE DATE"}
			var rows [][]string
			for _, item := range resp.Msg.GetProjectGrants() {
				rows = append(rows, []string{
					fmt.Sprint(item.GetOrganizationId()),
					fmt.Sprint(item.GetGrantedOrganizationId()),
					fmt.Sprint(item.GetProjectId()),
					fmt.Sprint(item.GetGrantedOrganizationName()),
					fmt.Sprint(item.GetProjectName()),
					fmt.Sprint(item.GetState().String()),
					func() string {
						if t := item.GetCreationDate(); t != nil {
							return t.AsTime().Format("2006-01-02T15:04:05Z")
						}
						return ""
					}(),
					func() string {
						if t := item.GetChangeDate(); t != nil {
							return t.AsTime().Format("2006-01-02T15:04:05Z")
						}
						return ""
					}(),
				})
			}
			output.Table(header, rows)
			return nil
		},
	}

	cmd.Flags().StringVar(&flag_ListProjectGrants_SortingColumn, "sorting-column", "", "SortingColumn is the field the result is sorted by. The default is the creation date. (one of: PROJECT_ID, CREATION_DATE, CHANGE_DATE)")
	_ = cmd.RegisterFlagCompletionFunc("sorting-column", func(_ *cobra.Command, _ []string, _ string) ([]string, cobra.ShellCompDirective) {
		return []string{"PROJECT_GRANT_FIELD_NAME_UNSPECIFIED", "PROJECT_GRANT_FIELD_NAME_PROJECT_ID", "PROJECT_GRANT_FIELD_NAME_CREATION_DATE", "PROJECT_GRANT_FIELD_NAME_CHANGE_DATE"}, cobra.ShellCompDirectiveNoFileComp
	})
	cmd.Flags().StringVar(&convFilter_ListProjectGrants_OrganizationIdFilter, "organization-id", "", "Filter by organization id")
	cmd.Flags().StringVar(&convFilter_ListProjectGrants_GrantedOrganizationIdFilter, "granted-organization-id", "", "Filter by granted organization id")

	return cmd
}
